"use client";

import React, { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { Author, Quote, PaginatedQuotes } from "@/lib/types";
import { getAuthor, getQuotesByAuthor, POPULAR_AUTHORS } from "@/lib/api/quotable";
import { QuoteCard } from "@/components/ui/QuoteCard";
import { Pagination } from "@/components/ui/Pagination";
import { AuthorCardSkeleton, QuoteListSkeleton } from "@/components/ui/Skeleton";
import { User, ExternalLink, BookOpen, ArrowLeft, Users } from "lucide-react";

export default function AuthorPage() {
  const params = useParams();
  const slug = params.slug as string;

  const [author, setAuthor] = useState<Author | null>(null);
  const [quotes, setQuotes] = useState<PaginatedQuotes | null>(null);
  const [loading, setLoading] = useState(true);
  const [quotesLoading, setQuotesLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [page, setPage] = useState(1);

  // Fetch author info
  useEffect(() => {
    const fetchAuthor = async () => {
      setLoading(true);
      setError(null);
      try {
        const data = await getAuthor(slug);
        setAuthor(data);
        if (!data) {
          setError("Author not found");
        }
      } catch (err) {
        setError(
          err instanceof Error ? err.message : "Failed to load author"
        );
      } finally {
        setLoading(false);
      }
    };

    fetchAuthor();
  }, [slug]);

  // Fetch author's quotes
  useEffect(() => {
    const fetchQuotes = async () => {
      setQuotesLoading(true);
      try {
        const data = await getQuotesByAuthor(slug, page, 10);
        setQuotes(data);
      } catch (err) {
        console.error("Failed to load quotes:", err);
      } finally {
        setQuotesLoading(false);
      }
    };

    fetchQuotes();
  }, [slug, page]);

  const handlePageChange = (newPage: number) => {
    setPage(newPage);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  if (loading) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
        <AuthorCardSkeleton />
        <div className="mt-12">
          <QuoteListSkeleton count={3} />
        </div>
      </div>
    );
  }

  if (error || !author) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center py-12"
        >
          <div className="inline-flex items-center justify-center w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full mb-6">
            <User className="w-10 h-10 text-gray-400" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100 mb-3">
            Author Not Found
          </h1>
          <p className="text-gray-600 dark:text-gray-400 mb-8 max-w-md mx-auto">
            We couldn&apos;t find an author with this name. They may not be in our database yet.
          </p>

          {/* Back Link */}
          <Link
            href="/search"
            className="inline-flex items-center gap-2 text-primary-600 dark:text-primary-400 hover:underline mb-8"
          >
            <ArrowLeft className="w-4 h-4" />
            Back to Search
          </Link>

          {/* Suggested Authors */}
          <div className="mt-8">
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-4 flex items-center justify-center gap-2">
              <Users className="w-4 h-4" />
              Try these popular authors:
            </p>
            <div className="flex flex-wrap justify-center gap-2">
              {POPULAR_AUTHORS.map((author) => (
                <Link
                  key={author.slug}
                  href={`/author/${author.slug}`}
                  className="px-4 py-2 bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 hover:border-primary-300 dark:hover:border-primary-600 text-sm font-medium text-gray-700 dark:text-gray-300 hover:text-primary-600 dark:hover:text-primary-400 transition-all"
                >
                  {author.name}
                </Link>
              ))}
            </div>
          </div>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
      {/* Back Link */}
      <motion.div
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        className="mb-6"
      >
        <Link
          href="/search"
          className="inline-flex items-center gap-2 text-gray-600 dark:text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
        >
          <ArrowLeft className="w-4 h-4" />
          Back to Search
        </Link>
      </motion.div>

      {/* Author Card */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-6 sm:p-8 border border-gray-100 dark:border-gray-700 mb-12"
      >
        <div className="flex flex-col sm:flex-row items-start gap-6">
          {/* Avatar */}
          <div className="flex-shrink-0">
            <div className="w-24 h-24 bg-gradient-to-br from-primary-500 to-accent-500 rounded-full flex items-center justify-center text-white text-3xl font-bold">
              {author.name.charAt(0)}
            </div>
          </div>

          {/* Info */}
          <div className="flex-1">
            <h1 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-gray-100 mb-2">
              {author.name}
            </h1>
            <p className="text-primary-600 dark:text-primary-400 font-medium mb-4">
              {author.description}
            </p>
            <p className="text-gray-600 dark:text-gray-400 leading-relaxed mb-4">
              {author.bio}
            </p>

            {/* Stats & Links */}
            <div className="flex flex-wrap items-center gap-4">
              <span className="inline-flex items-center gap-1 text-sm text-gray-500 dark:text-gray-400">
                <BookOpen className="w-4 h-4" />
                {author.quoteCount} quotes
              </span>
              {author.link && (
                <a
                  href={author.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-1 text-sm text-primary-600 dark:text-primary-400 hover:underline"
                >
                  <ExternalLink className="w-4 h-4" />
                  Learn more
                </a>
              )}
            </div>
          </div>
        </div>
      </motion.div>

      {/* Quotes Section */}
      <motion.section
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
      >
        <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 mb-6 flex items-center gap-2">
          <span className="w-1.5 h-6 bg-gradient-to-b from-primary-500 to-accent-500 rounded-full" />
          Quotes by {author.name}
        </h2>

        {quotesLoading ? (
          <QuoteListSkeleton count={3} />
        ) : quotes && quotes.results.length > 0 ? (
          <>
            <div className="space-y-6">
              <AnimatePresence mode="popLayout">
                {quotes.results.map((quote, index) => (
                  <QuoteCard
                    key={quote._id}
                    quote={quote}
                    animationDelay={index * 0.05}
                  />
                ))}
              </AnimatePresence>
            </div>

            {/* Custom Pagination */}
            {quotes.totalPages > 1 && (
              <div className="flex items-center justify-center gap-2 mt-8">
                <button
                  onClick={() => handlePageChange(page - 1)}
                  disabled={page === 1}
                  className="px-4 py-2 rounded-lg bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
                >
                  Previous
                </button>
                <span className="px-4 py-2 text-gray-600 dark:text-gray-400">
                  Page {page} of {quotes.totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(page + 1)}
                  disabled={page === quotes.totalPages}
                  className="px-4 py-2 rounded-lg bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
                >
                  Next
                </button>
              </div>
            )}
          </>
        ) : (
          <p className="text-center text-gray-500 dark:text-gray-400 py-8">
            No quotes found for this author.
          </p>
        )}
      </motion.section>
    </div>
  );
}
